############################################################ # Load Macros ############################################################ loadMacros( "PGstandard.pl", "PGML.pl", "AnswerFormatHelp.pl", "PGlateximage.pl", "PCCmacros.pl", "contextInequalitySetBuilder.pl", "Pd.pl", "PGcourse.pl", ); COMMENT('Authored in PreTeXt');
############################################################ # Header ############################################################ TEXT(beginproblem());
############################################################ # PG Setup Code ############################################################ $a = random(-7, 7); InequalitySetBuilder::UseVerticalSuchThat(); Context("InequalitySetBuilder-Only"); $set_builder = Compute("{ x | x >= $a}"); Context("Interval"); $interval = Compute("[$a, inf)");
$image_1 = createLaTeXImage(); $image_1->addToPreamble(latexImagePreamble()); $image_1->BEGIN_LATEX_IMAGE \begin{tikzpicture} \begin{axis} [ numberline, xlabel={\(x\)}, width=0.47\orccaprintwidth, ] \addplot[closedinfiniteinterval] coordinates {($a,0) (12,0)}; \end{axis} \end{tikzpicture}
END_LATEX_IMAGE
############################################################ # Body ############################################################
BEGIN_PGML Express the given interval in set-builder notation and interval notation.
>> [@image(insertGraph($image_1), width=>600, alt=>qq"a numberline with a shaded region; the shaded region begins at $a where there is a left bracket; it extends to the right all the way with an arrowhead")@]* <<
[@KeyboardInstructions('In set-builder notation:')@]**
[_]{$set_builder}{12}
[@KeyboardInstructions('In interval notation:')@]**
[_]{$interval}{12}
END_PGML
############################################################ # Solution ############################################################
BEGIN_PGML_SOLUTION The interval represents all numbers greater than or equal to [`[$a]\text{.}`] So in set-builder notation, the interval is [`[$set_builder]\text{.}`]
And we read the number line from left to right, with the shading starting at [`[$a]`] (and including [`[$a]`]) and extending on to [`\infty\text{.}`] So in interval notation, the interval is [`[$interval]\text{.}`]
END_PGML_SOLUTION
